const input = $input.first().json;
const endpointByStage = {
  linkedin_ingestion_csv: '/jobs/linkedin-ingestion/csv',
  linkedin_ingestion_mock: '/jobs/linkedin-ingestion/mock',
  identity_resolution: '/jobs/identity-resolution',
  intent_scoring: '/jobs/intent-scoring',
  opportunity_attribution: '/jobs/opportunity-attribution',
};
const stage = input.stage_name;
const endpoint = endpointByStage[stage];
if (!endpoint) throw new Error(`Unsupported stage_name: ${stage}`);
let body = {};
if (stage === 'linkedin_ingestion_csv') {
  if (!input.file) throw new Error('file is required for linkedin_ingestion_csv');
  body = { source: input.source || 'shield', file: input.file, delimiter: input.delimiter || ',' };
} else if (stage === 'linkedin_ingestion_mock') {
  body = { posts: Number(input.posts || 20), events: Number(input.events || 250) };
} else if (stage === 'opportunity_attribution') {
  body = { rebuild: Boolean(input.rebuild || false), window_days: Number(input.window_days || 30) };
} else {
  body = { rebuild: Boolean(input.rebuild || false) };
}
return [{ json: { ...input, endpoint, request_body: body } }];

const input = $input.first().json;
const baseUrl = String(input.api_base_url || '').replace(/\/$/, '');
const endpoint = input.endpoint;
const requestBody = input.request_body || {};
const pollIntervalSeconds = Number(input.poll_interval_seconds || 5);
const maxPollAttempts = Number(input.max_poll_attempts || 30);
const maxRunRetries = Number(input.max_run_retries || 0);
if (!baseUrl || !endpoint) throw new Error('api_base_url and endpoint are required');
let retry = 0;
let finalRun = null;
let failureReason = null;
while (retry <= maxRunRetries) {
  const startRes = await fetch(`${baseUrl}${endpoint}`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(requestBody) });
  if (!startRes.ok) {
    failureReason = `Start request failed (${startRes.status})`;
    retry += 1;
    continue;
  }
  const started = await startRes.json();
  const runId = started.run_id;
  if (!runId) {
    failureReason = 'Start request did not return run_id';
    retry += 1;
    continue;
  }
  let attempts = 0;
  while (attempts < maxPollAttempts) {
    attempts += 1;
    const pollRes = await fetch(`${baseUrl}/jobs/${runId}`, { method: 'GET' });
    if (!pollRes.ok) {
      failureReason = `Polling failed with status ${pollRes.status}`;
      break;
    }
    finalRun = await pollRes.json();
    if (finalRun.status === 'success') {
      return [{ json: { ...input, run: finalRun, final_status: 'success', run_retries_used: retry, poll_attempts: attempts } }];
    }
    if (finalRun.status === 'failed') {
      failureReason = finalRun.error_message || 'Run failed';
      break;
    }
    await new Promise((resolve) => setTimeout(resolve, pollIntervalSeconds * 1000));
  }
  retry += 1;
}
return [{ json: { ...input, run: finalRun, final_status: 'failed', run_retries_used: Math.max(0, retry - 1), failure_reason: failureReason || 'Unknown stage failure' } }];
